import openai
import os

def simple_chatbot(user_message, system_instructions="You are a helpful customer support assistant."):
    """
    Sends a user message to OpenAI's GPT model, concatenating system instructions.

    Args:
        user_message (str): The message from the user.
        system_instructions (str): Instructions for the GPT model's persona or task.

    Returns:
        str: The content of the model's response.
    """
    # Ensure the OpenAI API key is set
    # It's recommended to set this as an environment variable (OPENAI_API_KEY)
    # or pass it directly if managing multiple keys.
    # openai.api_key = os.getenv("OPENAI_API_KEY") 
    # If you need to set it directly for testing, uncomment the line below and replace 'YOUR_API_KEY'
    # openai.api_key = "YOUR_API_KEY" 

    try:
        response = openai.chat.completions.create(
            model="gpt-3.5-turbo",  # Or "gpt-4", "gpt-4o" etc. depending on your needs and access
            messages=[
                {"role": "system", "content": system_instructions},
                {"role": "user", "content": user_message}
            ],
            temperature=0.7, # Controls randomness. Lower values for more predictable responses.
            max_tokens=150 # Max tokens for the model's response
        )
        return response.choices[0].message.content
    except openai.RateLimitError:
        return "I'm currently experiencing high demand. Please try again in a moment."
    except openai.APIError as e:
        return f"An API error occurred: {e}"
    except Exception as e:
        return f"An unexpected error occurred: {e}"

if __name__ == "__main__":
    # --- Example Usage ---

    # IMPORTANT: Set your OpenAI API key before running
    # You can set it as an environment variable: export OPENAI_API_KEY='your-api-key'
    # Or uncomment the line below and replace 'YOUR_API_KEY' with your actual key
    # openai.api_key = "YOUR_API_KEY"

    if openai.api_key is None:
        print("Please set your OPENAI_API_KEY environment variable or hardcode it in the script.")
        print("You can get your API key from https://platform.openai.com/api-keys")
        exit()

    print("Welcome to the Customer Support Chatbot!")
    print("Type 'exit' or 'quit' to end the conversation.")

    while True:
        user_input = input("You: ")
        if user_input.lower() in ["exit", "quit"]:
            print("Chatbot: Goodbye!")
            break

        # Define specific system instructions for your customer support assistant
        cs_instructions = (
            "You are a friendly and helpful customer support assistant for a retail company. "
            "Your goal is to assist customers with product inquiries, order status, returns, "
            "and general support. Always maintain a polite and professional tone. "
            "If you cannot provide a definitive answer, suggest checking the FAQ or contacting a human representative."
        )

        chatbot_response = simple_chatbot(user_input, cs_instructions)
        print(f"Chatbot: {chatbot_response}")